<?php
define('KEY','ibook2026deploy');
if(($_GET['key']??'')!==KEY){http_response_code(403);die('Akses ditolak.');}
header('Content-Type: text/html; charset=utf-8');
echo '<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{font-family:monospace;background:#1a1a2e;color:#e5e7eb;padding:20px}.ok{color:#34d399}.fail{color:#f87171}</style></head><body>';
echo '<h2 style="color:#f59e0b">Fix: Pre-fill tarikh & bilik dari Jadual Minggu</h2>';
$root=__DIR__;
if(!file_exists($root.'/artisan')&&file_exists(dirname($root).'/artisan'))$root=dirname($root);
$files=[
    'app/Http/Controllers/TempahanController.php' => '',
    'resources/views/tempahan/create.blade.php'   => '',
];
$ok=0;$fail=0;
foreach($files as $rel=>$b64key){
    $path=$root.'/'.$rel;
    $content=base64_decode($b64key);
    if(!$content){echo '<p class="fail">GAGAL decode: '.$rel.'</p>';$fail++;continue;}
    $bytes=file_put_contents($path,$content);
    if($bytes===false){echo '<p class="fail">GAGAL tulis: '.$rel.'</p>';$fail++;}
    else{echo '<p class="ok">&#10003; '.$rel.' ('.$bytes.' bytes)</p>';$ok++;}
}
$viewsDir=$root.'/storage/framework/views';$cleared=0;
if(is_dir($viewsDir)){foreach(glob($viewsDir.'/*.php')as $f){@unlink($f)&&$cleared++;}}
echo '<p class="ok">&#10003; Blade cache ('.$cleared.' fail dikosongkan)</p>';
echo '<p style="color:#94a3b8;margin-top:12px">OK: '.$ok.' | Gagal: '.$fail.'</p>';
echo '<p style="color:#fbbf24;margin-top:8px">Test: Klik slot hijau dalam Jadual Minggu &#8594; form sepatutnya pre-fill tarikh, bilik &amp; sesi.</p>';
@unlink(__FILE__);
echo '<p class="ok">&#10003; Patcher dipadam.</p></body></html>';